import React from 'react';

export interface SidebarProps {
  onDragStart: (event: React.DragEvent<HTMLDivElement>, subtype: string) => void;
}

// a list of draggable items we support today
const ITEMS: Array<{ label: string; subtype: string }> = [
  { label: 'AWS Provider', subtype: 'aws' },
  { label: 'GCP Provider', subtype: 'gcp' },
  { label: 'Azure Provider', subtype: 'azure' },
  { label: 'Compute Service', subtype: 'compute' },
  { label: 'Network Service', subtype: 'network' },
  { label: 'Storage Service', subtype: 'storage' },
];

export default function Sidebar({ onDragStart }: SidebarProps) {
  return (
    <aside className="sidebar">
      <div className="description">Drag any item onto the canvas</div>
      {ITEMS.map((item) => (
        <div
          key={item.subtype}
          className="dndnode"
          onDragStart={(event) => onDragStart(event, item.subtype)}
          draggable
        >
          {item.label}
        </div>
      ))}
    </aside>
  );
}
